import { MapPin, Clock } from 'lucide-react';

export default function IncidentCard({ incident, onAccept }) {
  return (
    <div className="bg-white p-4 rounded-3xl shadow-sm border border-gray-100 flex gap-4 transition hover:shadow-md">
      <img src={incident.imageUrl} alt="Animal" className="w-24 h-24 rounded-2xl object-cover shadow-sm" />
      <div className="flex-1">
        <div className="flex justify-between items-start">
          <h3 className="font-bold text-lg text-gray-800">Injured {incident.animalType}</h3>
          <span className="text-xs bg-red-100 text-red-600 px-2 py-1 rounded-full font-bold">NEW</span>
        </div>
        <p className="text-sm text-gray-500 flex items-center gap-1 mt-1">
          <MapPin size={14} className="text-green-500"/> ~1.5 km away
        </p>
        <button 
          onClick={() => onAccept(incident.incidentId)}
          className="mt-3 w-full bg-green-600 text-white py-2 rounded-xl text-sm font-bold active:scale-95 transition"
        >
          Accept Rescue
        </button>
      </div>
    </div>
  );
}
